package com.dimensionalcortex.udac;

import android.accessibilityservice.AccessibilityService;
import android.accessibilityservice.AccessibilityServiceInfo;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;
import android.view.accessibility.AccessibilityEvent;
import android.view.accessibility.AccessibilityNodeInfo;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;

import org.json.JSONObject;

/**
 * UDAC Accessibility Service - AGGRESSIVE DEBUG VERSION
 * ======================================================
 * 
 * Changes:
 * 1. EXPANDED platform detection (more package names)
 * 2. BETTER send button detection (more patterns)
 * 3. VERBOSE logging for debugging
 * 4. Longer timeout for injection
 * 5. Always attempts injection on any button click in chat apps
 */
public class UDACAccessibilityService extends AccessibilityService {

    private static final String TAG = "UDAC";

    private static final String BACKEND_BASE = "http://127.0.0.1:7013";
    private static final String EVENT_ENDPOINT = BACKEND_BASE + "/udac/event";
    private static final String INJECT_ENDPOINT = BACKEND_BASE + "/udac/inject";

    // === EXPANDED: More package names ===
    private static final Set<String> TARGET_PACKAGES = new HashSet<>();
    static {
        // ChatGPT
        TARGET_PACKAGES.add("com.openai.chatgpt");
        TARGET_PACKAGES.add("com.openai.chatgpt.debug");
        TARGET_PACKAGES.add("com.openai.chat");

        // Claude
        TARGET_PACKAGES.add("com.anthropic.claude");
        TARGET_PACKAGES.add("com.anthropic.claude.debug");

        // Perplexity
        TARGET_PACKAGES.add("ai.perplexity.app.android");
        TARGET_PACKAGES.add("ai.perplexity.app");

        // Google Gemini / Bard
        TARGET_PACKAGES.add("com.google.android.apps.bard");
        TARGET_PACKAGES.add("com.google.android.apps.gemini");
        TARGET_PACKAGES.add("com.google.android.apps.aistudio");

        // Bing / Copilot
        TARGET_PACKAGES.add("com.microsoft.bing");
        TARGET_PACKAGES.add("com.microsoft.copilot");

        // Poe
        TARGET_PACKAGES.add("com.quora.poe");

        // Character.AI
        TARGET_PACKAGES.add("ai.character.app");

        // Pi
        TARGET_PACKAGES.add("ai.inflection.pi");

        // Replika
        TARGET_PACKAGES.add("ai.replika.app");
    }

    private static final Map<String, String> PLATFORM_NAMES = new HashMap<>();
    static {
        PLATFORM_NAMES.put("com.openai.chatgpt", "ChatGPT");
        PLATFORM_NAMES.put("com.openai.chatgpt.debug", "ChatGPT");
        PLATFORM_NAMES.put("com.openai.chat", "ChatGPT");
        PLATFORM_NAMES.put("com.anthropic.claude", "Claude");
        PLATFORM_NAMES.put("com.anthropic.claude.debug", "Claude");
        PLATFORM_NAMES.put("ai.perplexity.app.android", "Perplexity");
        PLATFORM_NAMES.put("ai.perplexity.app", "Perplexity");
        PLATFORM_NAMES.put("com.google.android.apps.bard", "Gemini");
        PLATFORM_NAMES.put("com.google.android.apps.gemini", "Gemini");
        PLATFORM_NAMES.put("com.google.android.apps.aistudio", "Gemini");
        PLATFORM_NAMES.put("com.microsoft.bing", "Copilot");
        PLATFORM_NAMES.put("com.microsoft.copilot", "Copilot");
        PLATFORM_NAMES.put("com.quora.poe", "Poe");
        PLATFORM_NAMES.put("ai.character.app", "CharacterAI");
        PLATFORM_NAMES.put("ai.inflection.pi", "Pi");
        PLATFORM_NAMES.put("ai.replika.app", "Replika");
    }

    // === EXPANDED: Send button patterns ===
    private static final Set<String> SEND_BUTTON_IDS = new HashSet<>();
    static {
        SEND_BUTTON_IDS.add("send");
        SEND_BUTTON_IDS.add("submit");
        SEND_BUTTON_IDS.add("btn_send");
        SEND_BUTTON_IDS.add("button_send");
        SEND_BUTTON_IDS.add("send_button");
        SEND_BUTTON_IDS.add("sendButton");
        SEND_BUTTON_IDS.add("fab_send");
        SEND_BUTTON_IDS.add("action_send");
        SEND_BUTTON_IDS.add("send_message");
        SEND_BUTTON_IDS.add("post");
        SEND_BUTTON_IDS.add("arrow");
        SEND_BUTTON_IDS.add("enter");
        SEND_BUTTON_IDS.add("submit_button");
        SEND_BUTTON_IDS.add("chat_send");
        SEND_BUTTON_IDS.add("message_send");
        SEND_BUTTON_IDS.add("input_send");
    }

    private static final Set<String> SEND_BUTTON_DESCRIPTIONS = new HashSet<>();
    static {
        SEND_BUTTON_DESCRIPTIONS.add("send");
        SEND_BUTTON_DESCRIPTIONS.add("submit");
        SEND_BUTTON_DESCRIPTIONS.add("post");
        SEND_BUTTON_DESCRIPTIONS.add("send message");
        SEND_BUTTON_DESCRIPTIONS.add("send button");
        SEND_BUTTON_DESCRIPTIONS.add("arrow");
        SEND_BUTTON_DESCRIPTIONS.add("enter");
        SEND_BUTTON_DESCRIPTIONS.add("go");
        SEND_BUTTON_DESCRIPTIONS.add("done");
    }

    private ExecutorService networkExecutor;
    private Handler mainHandler;

    // Debouncing
    private String lastCapturedHash = "";
    private long lastCaptureTime = 0;
    private static final long DEBOUNCE_MS = 300;

    // Input tracking
    private volatile AccessibilityNodeInfo currentInputField = null;
    private volatile String currentPackage = "";
    private volatile String lastUserMessage = "";
    private final Object inputLock = new Object();

    // Feature flags
    private boolean captureEnabled = true;
    private boolean injectionEnabled = true;

    // Timing
    private static final int INJECTION_TIMEOUT_MS = 3000;

    // Debug
    private int eventCount = 0;
    private int injectionAttempts = 0;
    private int injectionSuccesses = 0;

    @Override
    public void onCreate() {
        super.onCreate();
        networkExecutor = Executors.newFixedThreadPool(3);
        mainHandler = new Handler(Looper.getMainLooper());
        Log.i(TAG, "========================================");
        Log.i(TAG, "UDAC Service CREATED - AGGRESSIVE DEBUG");
        Log.i(TAG, "Monitoring " + TARGET_PACKAGES.size() + " packages");
        Log.i(TAG, "========================================");
    }

    @Override
    public void onServiceConnected() {
        super.onServiceConnected();

        AccessibilityServiceInfo info = getServiceInfo();
        if (info != null) {
            // Watch ALL event types
            info.eventTypes = AccessibilityEvent.TYPES_ALL_MASK;

            info.feedbackType = AccessibilityServiceInfo.FEEDBACK_GENERIC;

            info.flags = AccessibilityServiceInfo.FLAG_REPORT_VIEW_IDS
                    | AccessibilityServiceInfo.FLAG_RETRIEVE_INTERACTIVE_WINDOWS
                    | AccessibilityServiceInfo.FLAG_INCLUDE_NOT_IMPORTANT_VIEWS
                    | AccessibilityServiceInfo.FLAG_REQUEST_ENHANCED_WEB_ACCESSIBILITY;

            info.notificationTimeout = 50;
            setServiceInfo(info);
        }

        Log.i(TAG, "========================================");
        Log.i(TAG, "UDAC Service CONNECTED");
        Log.i(TAG, "Capture: " + captureEnabled);
        Log.i(TAG, "Injection: " + injectionEnabled);
        Log.i(TAG, "========================================");

        sendCaptureEvent("UDAC_SERVICE", "Service connected - AGGRESSIVE DEBUG", 0);
    }

    @Override
    public void onAccessibilityEvent(AccessibilityEvent event) {
        if (event == null) return;

        CharSequence pkgSeq = event.getPackageName();
        if (pkgSeq == null) return;

        String packageName = pkgSeq.toString();

        // Check if this is a target package
        if (!TARGET_PACKAGES.contains(packageName)) {
            return;
        }

        eventCount++;
        currentPackage = packageName;
        int eventType = event.getEventType();

        // Log every 10th event to avoid spam
        if (eventCount % 10 == 0) {
            String platformName = PLATFORM_NAMES.getOrDefault(packageName, packageName);
            Log.d(TAG, String.format("[%d] Event %d from %s", eventCount, eventType, platformName));
        }

        switch (eventType) {
            case AccessibilityEvent.TYPE_VIEW_FOCUSED:
                handleFocus(event);
                break;

            case AccessibilityEvent.TYPE_VIEW_TEXT_CHANGED:
                handleTextChange(event);
                break;

            case AccessibilityEvent.TYPE_VIEW_CLICKED:
                handleClick(event, packageName);
                break;

            case AccessibilityEvent.TYPE_WINDOW_CONTENT_CHANGED:
                if (captureEnabled) {
                    handleContentChange(event, packageName);
                }
                break;

            case AccessibilityEvent.TYPE_VIEW_TEXT_SELECTION_CHANGED:
                // Track selection in input field
                handleTextSelection(event);
                break;
        }
    }

    private void handleFocus(AccessibilityEvent event) {
        AccessibilityNodeInfo source = event.getSource();
        if (source == null) return;

        try {
            if (source.isEditable()) {
                synchronized (inputLock) {
                    if (currentInputField != null && currentInputField != source) {
                        try { currentInputField.recycle(); } catch (Exception e) {}
                    }
                    currentInputField = source;

                    CharSequence text = source.getText();
                    lastUserMessage = text != null ? text.toString() : "";

                    Log.d(TAG, "FOCUS on input field, text: '" + truncate(lastUserMessage, 30) + "'");
                }
                return; // Don't recycle - we're keeping it
            }
        } catch (Exception e) {
            Log.e(TAG, "Focus error: " + e.getMessage());
        }

        source.recycle();
    }

    private void handleTextChange(AccessibilityEvent event) {
        AccessibilityNodeInfo source = event.getSource();
        if (source == null) return;

        try {
            if (source.isEditable()) {
                synchronized (inputLock) {
                    if (currentInputField != null && currentInputField != source) {
                        try { currentInputField.recycle(); } catch (Exception e) {}
                    }
                    currentInputField = source;

                    CharSequence text = source.getText();
                    if (text != null) {
                        lastUserMessage = text.toString();
                        Log.d(TAG, "TEXT CHANGED: '" + truncate(lastUserMessage, 50) + "'");
                    }
                }
                return;
            }
        } catch (Exception e) {
            Log.e(TAG, "Text change error: " + e.getMessage());
        }

        source.recycle();
    }

    private void handleTextSelection(AccessibilityEvent event) {
        // Update message if selection changes in editable field
        AccessibilityNodeInfo source = event.getSource();
        if (source == null) return;

        try {
            if (source.isEditable()) {
                CharSequence text = source.getText();
                if (text != null) {
                    synchronized (inputLock) {
                        lastUserMessage = text.toString();
                    }
                }
            }
        } catch (Exception e) {
            // Ignore
        } finally {
            source.recycle();
        }
    }

    private void handleClick(AccessibilityEvent event, String packageName) {
        AccessibilityNodeInfo source = event.getSource();
        if (source == null) return;

        try {
            String platformName = PLATFORM_NAMES.getOrDefault(packageName, "Unknown");

            // Get node info for logging
            String className = source.getClassName() != null ? source.getClassName().toString() : "";
            String viewId = source.getViewIdResourceName();
            CharSequence contentDesc = source.getContentDescription();
            CharSequence text = source.getText();

            Log.d(TAG, "CLICK detected:");
            Log.d(TAG, "  Class: " + className);
            Log.d(TAG, "  ID: " + viewId);
            Log.d(TAG, "  Desc: " + contentDesc);
            Log.d(TAG, "  Text: " + text);

            // Check if this looks like a send button
            boolean isSend = isSendButton(source);
            Log.d(TAG, "  Is send button: " + isSend);

            if (isSend && injectionEnabled) {
                Log.i(TAG, "========================================");
                Log.i(TAG, "SEND BUTTON CLICKED on " + platformName);
                Log.i(TAG, "========================================");

                performInjection(packageName);
            }

        } finally {
            source.recycle();
        }
    }

    private boolean isSendButton(AccessibilityNodeInfo node) {
        String viewId = node.getViewIdResourceName();
        CharSequence contentDesc = node.getContentDescription();
        CharSequence text = node.getText();
        String className = node.getClassName() != null ? node.getClassName().toString() : "";

        // Check view ID
        if (viewId != null) {
            String idLower = viewId.toLowerCase();
            for (String pattern : SEND_BUTTON_IDS) {
                if (idLower.contains(pattern)) {
                    Log.d(TAG, "  Matched ID pattern: " + pattern);
                    return true;
                }
            }
        }

        // Check content description
        if (contentDesc != null) {
            String descLower = contentDesc.toString().toLowerCase();
            for (String pattern : SEND_BUTTON_DESCRIPTIONS) {
                if (descLower.contains(pattern)) {
                    Log.d(TAG, "  Matched desc pattern: " + pattern);
                    return true;
                }
            }
        }

        // Check button text
        if (text != null) {
            String textLower = text.toString().toLowerCase();
            if (textLower.equals("send") || textLower.equals("submit") || 
                textLower.equals("post") || textLower.equals("go")) {
                Log.d(TAG, "  Matched text: " + textLower);
                return true;
            }
        }

        // Check if it's a button-like class
        boolean isButtonClass = className.contains("Button") || 
                               className.contains("ImageView") ||
                               className.contains("FloatingActionButton");

        // If it's a button in a chat app and we have a message ready, assume it might be send
        if (isButtonClass && lastUserMessage != null && !lastUserMessage.isEmpty()) {
            // Check if it's clickable and looks interactive
            if (node.isClickable() && (contentDesc != null || viewId != null)) {
                Log.d(TAG, "  Assuming button is send (have message ready)");
                return true;
            }
        }

        return false;
    }

    private void performInjection(String packageName) {
        injectionAttempts++;

        final String userMessage;
        final AccessibilityNodeInfo inputField;

        synchronized (inputLock) {
            userMessage = lastUserMessage;
            inputField = currentInputField;
        }

        if (inputField == null) {
            Log.w(TAG, "No input field tracked!");
            return;
        }

        if (userMessage == null || userMessage.trim().isEmpty()) {
            Log.d(TAG, "Empty message, skipping injection");
            return;
        }

        final String platform = PLATFORM_NAMES.getOrDefault(packageName, "Unknown");

        Log.i(TAG, "Requesting injection:");
        Log.i(TAG, "  Platform: " + platform);
        Log.i(TAG, "  Message: '" + truncate(userMessage, 60) + "'");

        // Synchronous injection
        final CountDownLatch latch = new CountDownLatch(1);
        final AtomicReference<String> injectedRef = new AtomicReference<>(null);
        final AtomicReference<Boolean> successRef = new AtomicReference<>(false);

        networkExecutor.execute(() -> {
            try {
                InjectionResult result = requestInjection(userMessage, platform);

                if (result != null) {
                    Log.i(TAG, "Injection response received:");
                    Log.i(TAG, "  Was injected: " + result.wasInjected);
                    Log.i(TAG, "  Relevance: " + result.relevance);

                    if (result.wasInjected && result.injectedMessage != null) {
                        injectedRef.set(result.injectedMessage);
                        successRef.set(true);
                        Log.i(TAG, "  Injected message length: " + result.injectedMessage.length());
                    }
                } else {
                    Log.w(TAG, "Injection request returned null");
                }
            } catch (Exception e) {
                Log.e(TAG, "Injection error: " + e.getMessage());
            } finally {
                latch.countDown();
            }
        });

        // Wait for response
        try {
            boolean completed = latch.await(INJECTION_TIMEOUT_MS, TimeUnit.MILLISECONDS);
            if (!completed) {
                Log.w(TAG, "Injection request timed out!");
                return;
            }
        } catch (InterruptedException e) {
            Log.w(TAG, "Injection wait interrupted");
            return;
        }

        // Write to input field if injection succeeded
        if (successRef.get() && injectedRef.get() != null) {
            final String finalMessage = injectedRef.get();

            Log.i(TAG, "========================================");
            Log.i(TAG, "WRITING INJECTED MESSAGE TO INPUT");
            Log.i(TAG, "  Original length: " + userMessage.length());
            Log.i(TAG, "  Final length: " + finalMessage.length());
            Log.i(TAG, "========================================");

            mainHandler.post(() -> {
                boolean written = writeToInputField(inputField, finalMessage);
                if (written) {
                    injectionSuccesses++;
                    Log.i(TAG, "✅ INJECTION WRITTEN! Total: " + injectionSuccesses + "/" + injectionAttempts);
                } else {
                    Log.e(TAG, "❌ INJECTION WRITE FAILED");
                }
            });

            // Small delay for write to complete
            try { Thread.sleep(150); } catch (InterruptedException e) {}
        } else {
            Log.d(TAG, "No injection to write (below threshold or no context)");
        }
    }

    private boolean writeToInputField(AccessibilityNodeInfo inputField, String text) {
        if (inputField == null) {
            Log.e(TAG, "Input field is null!");
            return false;
        }

        try {
            Bundle args = new Bundle();
            args.putCharSequence(
                AccessibilityNodeInfo.ACTION_ARGUMENT_SET_TEXT_CHARSEQUENCE,
                text
            );

            boolean success = inputField.performAction(
                AccessibilityNodeInfo.ACTION_SET_TEXT,
                args
            );

            if (success) {
                Log.i(TAG, "ACTION_SET_TEXT succeeded");
                synchronized (inputLock) {
                    lastUserMessage = text;
                }
                return true;
            }

            Log.w(TAG, "ACTION_SET_TEXT returned false, trying focus+set");

            // Try with focus first
            inputField.performAction(AccessibilityNodeInfo.ACTION_FOCUS);
            Thread.sleep(50);

            return inputField.performAction(AccessibilityNodeInfo.ACTION_SET_TEXT, args);

        } catch (Exception e) {
            Log.e(TAG, "Write error: " + e.getMessage());
            return false;
        }
    }

    private void handleContentChange(AccessibilityEvent event, String packageName) {
        String text = extractText(event);
        if (text == null || text.trim().length() < 5) return;

        // Debounce
        String hash = String.valueOf(text.hashCode());
        long now = System.currentTimeMillis();
        if (hash.equals(lastCapturedHash) && (now - lastCaptureTime) < DEBOUNCE_MS) {
            return;
        }
        lastCapturedHash = hash;
        lastCaptureTime = now;

        // Skip user's own input
        synchronized (inputLock) {
            if (lastUserMessage != null && !lastUserMessage.isEmpty()) {
                if (text.contains(lastUserMessage)) {
                    return;
                }
            }
        }

        String platformName = PLATFORM_NAMES.getOrDefault(packageName, packageName);
        Log.d(TAG, "CAPTURED from " + platformName + ": " + truncate(text, 60));

        sendCaptureEvent(packageName, text, event.getEventType());
    }

    private static class InjectionResult {
        String originalMessage;
        String injectedMessage;
        String contextBlock;
        boolean wasInjected;
        double relevance;
    }

    private InjectionResult requestInjection(String message, String platform) {
        HttpURLConnection conn = null;
        try {
            JSONObject payload = new JSONObject();
            payload.put("message", message);
            payload.put("platform", platform);
            payload.put("timestamp", System.currentTimeMillis());

            Log.d(TAG, "Sending injection request to " + INJECT_ENDPOINT);

            URL url = new URL(INJECT_ENDPOINT);
            conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("POST");
            conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
            conn.setDoOutput(true);
            conn.setDoInput(true);
            conn.setConnectTimeout(INJECTION_TIMEOUT_MS);
            conn.setReadTimeout(INJECTION_TIMEOUT_MS);

            try (OutputStream os = conn.getOutputStream()) {
                os.write(payload.toString().getBytes(StandardCharsets.UTF_8));
            }

            int responseCode = conn.getResponseCode();
            Log.d(TAG, "Injection response code: " + responseCode);

            if (responseCode == HttpURLConnection.HTTP_OK) {
                BufferedReader reader = new BufferedReader(
                    new InputStreamReader(conn.getInputStream(), StandardCharsets.UTF_8)
                );
                StringBuilder sb = new StringBuilder();
                String line;
                while ((line = reader.readLine()) != null) {
                    sb.append(line);
                }
                reader.close();

                String responseBody = sb.toString();
                Log.d(TAG, "Response: " + truncate(responseBody, 200));

                JSONObject response = new JSONObject(responseBody);

                InjectionResult result = new InjectionResult();
                result.originalMessage = response.optString("original_message", message);
                result.injectedMessage = response.optString("injected_message", message);
                result.contextBlock = response.optString("context_block", "");
                result.wasInjected = response.optBoolean("injected", false);
                result.relevance = response.optDouble("relevance", 0.0);

                return result;
            } else {
                Log.w(TAG, "Non-200 response: " + responseCode);
            }

        } catch (Exception e) {
            Log.e(TAG, "Injection request failed: " + e.getMessage());
        } finally {
            if (conn != null) conn.disconnect();
        }

        return null;
    }

    private String extractText(AccessibilityEvent event) {
        StringBuilder sb = new StringBuilder();

        if (event.getText() != null) {
            for (CharSequence t : event.getText()) {
                if (t != null && t.length() > 0) {
                    sb.append(t).append(" ");
                }
            }
        }

        CharSequence cd = event.getContentDescription();
        if (cd != null && cd.length() > 0) {
            sb.append(cd).append(" ");
        }

        AccessibilityNodeInfo source = event.getSource();
        if (source != null) {
            sb.append(extractFromNode(source, 0));
            source.recycle();
        }

        return sb.toString().trim();
    }

    private String extractFromNode(AccessibilityNodeInfo node, int depth) {
        if (node == null || depth > 5) return "";

        StringBuilder sb = new StringBuilder();

        // Skip input field
        synchronized (inputLock) {
            if (currentInputField != null && node.equals(currentInputField)) {
                return "";
            }
        }

        CharSequence text = node.getText();
        if (text != null && text.length() > 0) {
            sb.append(text).append(" ");
        }

        int count = Math.min(node.getChildCount(), 20);
        for (int i = 0; i < count; i++) {
            AccessibilityNodeInfo child = node.getChild(i);
            if (child != null) {
                sb.append(extractFromNode(child, depth + 1));
                child.recycle();
            }
        }

        return sb.toString();
    }

    private void sendCaptureEvent(String sourceApp, String text, int eventType) {
        networkExecutor.execute(() -> {
            HttpURLConnection conn = null;
            try {
                JSONObject payload = new JSONObject();
                payload.put("source_app", sourceApp);
                payload.put("text", text);
                payload.put("event_type", eventType);
                payload.put("timestamp", System.currentTimeMillis());

                URL url = new URL(EVENT_ENDPOINT);
                conn = (HttpURLConnection) url.openConnection();
                conn.setRequestMethod("POST");
                conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
                conn.setDoOutput(true);
                conn.setConnectTimeout(5000);
                conn.setReadTimeout(5000);

                try (OutputStream os = conn.getOutputStream()) {
                    os.write(payload.toString().getBytes(StandardCharsets.UTF_8));
                }

                int code = conn.getResponseCode();
                if (code == 200) {
                    Log.d(TAG, "Capture sent OK");
                }

            } catch (Exception e) {
                // Backend may not be running
            } finally {
                if (conn != null) conn.disconnect();
            }
        });
    }

    private String truncate(String s, int max) {
        if (s == null) return "(null)";
        return s.length() <= max ? s : s.substring(0, max) + "...";
    }

    @Override
    public void onInterrupt() {
        Log.w(TAG, "Service interrupted");
    }

    @Override
    public void onDestroy() {
        super.onDestroy();

        Log.i(TAG, "========================================");
        Log.i(TAG, "UDAC Service DESTROYED");
        Log.i(TAG, "  Events processed: " + eventCount);
        Log.i(TAG, "  Injection attempts: " + injectionAttempts);
        Log.i(TAG, "  Injection successes: " + injectionSuccesses);
        Log.i(TAG, "========================================");

        synchronized (inputLock) {
            if (currentInputField != null) {
                try { currentInputField.recycle(); } catch (Exception e) {}
                currentInputField = null;
            }
        }

        if (networkExecutor != null) {
            networkExecutor.shutdown();
        }
    }
}

