import android.accessibilityservice.AccessibilityService;
import android.accessibilityservice.AccessibilityServiceInfo;
import android.util.Log;
import android.view.accessibility.AccessibilityEvent;

import java.io.OutputStreamWriter;
import java.net.HttpURLConnection;
import java.net.URL;

public class UDACAccessibilityService extends AccessibilityService {

    private static final String TAG = "UDAC";

    @Override
    public void onServiceConnected() {
        super.onServiceConnected();
        AccessibilityServiceInfo info = new AccessibilityServiceInfo();

        info.eventTypes =
                AccessibilityEvent.TYPE_VIEW_TEXT_CHANGED
                        | AccessibilityEvent.TYPE_WINDOW_CONTENT_CHANGED
                        | AccessibilityEvent.TYPE_VIEW_FOCUSED
                        | AccessibilityEvent.TYPE_VIEW_CLICKED;

        info.feedbackType = AccessibilityServiceInfo.FEEDBACK_GENERIC;
        info.flags = AccessibilityServiceInfo.FLAG_REPORT_VIEW_IDS
                | AccessibilityServiceInfo.FLAG_RETRIEVE_INTERACTIVE_WINDOWS;
        info.notificationTimeout = 50;

        setServiceInfo(info);
        Log.i(TAG, "UDACAccessibilityService connected");
    }

    @Override
    public void onAccessibilityEvent(AccessibilityEvent event) {
        if (event == null) return;

        CharSequence pkgName = event.getPackageName();
        String pkg = (pkgName != null) ? pkgName.toString() : "";

        if (event.getText() == null || event.getText().isEmpty()) {
            return;
        }

        StringBuilder sb = new StringBuilder();
        for (CharSequence cs : event.getText()) {
            if (cs != null) {
                if (sb.length() > 0) sb.append(' ');
                sb.append(cs.toString());
            }
        }

        String text = sb.toString().trim();
        if (text.isEmpty()) return;

        sendToUdac(pkg, text);
    }

    private void sendToUdac(String pkg, String text) {
        HttpURLConnection conn = null;
        try {
            URL url = new URL("http://127.0.0.1:7013/udac/event");
            conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("POST");
            conn.setDoOutput(true);
            conn.setConnectTimeout(500);
            conn.setReadTimeout(1000);
            conn.setRequestProperty("Content-Type", "application/json; charset=utf-8");

            String safeText = text.replace("\\", "\\\\").replace("\"", "\\\"");
            String safePkg = pkg.replace("\\", "\\\\").replace("\"", "\\\"");
            String payload = "{\"text\":\"" + safeText + "\",\"source_app\":\"" + safePkg + "\"}";

            OutputStreamWriter writer = new OutputStreamWriter(conn.getOutputStream(), "UTF-8");
            try {
                writer.write(payload);
                writer.flush();
            } finally {
                writer.close();
            }

            int code = conn.getResponseCode();
            Log.d(TAG, "Sent event to UDAC: code=" + code);
        } catch (Exception e) {
            Log.e(TAG, "Error sending to UDAC: " + e.getMessage());
        } finally {
            if (conn != null) {
                try { conn.disconnect(); } catch (Exception ignore) {}
            }
        }
    }

    @Override
    public void onInterrupt() {
        Log.w(TAG, "UDACAccessibilityService interrupted");
    }
